import Axios from 'axios';
import './App.css';

  function Application() {

  const [donnee_id, setDonnee_id] = useState([]);
  const [donnee_etablissementType, setDonnee_etablissementType] = useState([]);
  const [donnee_etablissement, setDonnee_etablissement] = useState([]);
  const [donnee_location, setDonnee_location] = useState([]);
  const [donnee_address, setDonnee_address] = useState([]);
  const [donnee_mail, setDonnee_mail] = useState([]);

  const Obtenir_element_nom = () => {
    Axios.get("http://localhost:3001/api/utilisateur/${etablissement}").then((response) => {

      setDonnee_id(response.data.id)
      setDonnee_etablissementType(response.data.etablissementType)
      setDonnee_etablissement(response.data.etablissement)
      setDonnee_location(response.data.location)
      setDonnee_address(response.data.address)
      setDonnee_mail(response.data.mail)
 })
 }

  return (
  <Table>
   <Thead>
    <Tr>
      <Th>id</Th>
      <Th>etablissement_type</Th>
      <Th>etablissement</Th>
      <Th>location</Th>
      <Th>address</Th>
      <Th>mail</Th>
    </Tr>
   </Thead>

   <Tbody>
    <Tr>
     <Td>{donnee_id}</Td>
     <Td>{donnee_etablissementType}</Td>
     <Td>{donnee_etablissement}</Td>
     <Td>{donnee_location}</Td>
     <Td>{donnee_address}</Td>
     <Td>{donnee_mail}</Td>
    </Tr>
   </Tbody>
  </Table>

  );
}

export default Application;
